arguments.new_str:
protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // Preserve "Discriminator" property name so existing documents and
    // raw SQL queries like "WHERE c.Discriminator = 'Blog'" keep working.
    modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

    // Preserve the old compound id format ("Blog|1") so existing documents
    // remain accessible via FindAsync and point-reads.
    modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);

    // HasIndex removed — Cosmos DB threw at startup in EF Core 9.
    // Manage indexing via the container's indexing policy instead.
}

